            /* No new frame but within timeout: hold previous state */
            output.heater_on = controller->heater_on;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = false;
            output.timed_out = controller->timed_out;
            return output;
        }
        /* No valid sensor and no timeout event: stay safe off */
        controller_set_safe_off(controller);
        break;

    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_sensor = true;
        controller->timed_out = false;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        int temp = input.temperature_c;

        /* If temperature is below low threshold, heat */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        }
        /* If temperature is above high threshold, safe off */
        else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            controller_set_safe_off(controller);
        }
        /* If 47 <= temp < 50: hold previous state */
        else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            controller->state = CONTROLLER_STATE_HOLDING;
            /* heater_on remains unchanged */
        }
        /* If 50 <= temp <= 52: check for rising temperature */
        else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            controller->state = CONTROLLER_STATE_HOLDING;
            /* Check if temperature is rising compared to previous sample */
            bool is_rising = false;
            if (controller->last_temperature_c != 0 || input.temperature_c >= controller->last_temperature_c) {
                /* Rising if current >= last and we have a prior reading */
                /* Special case: if this is the first valid reading, don't treat as rising */
                if (controller->last_temperature_c > 0 && input.temperature_c >= controller->last_temperature_c) {
                    is_rising = true;
                } else if (controller->last_temperature_c == 0) {
                    /* First valid reading - don't treat as rising yet */
                    is_rising = false;
                }
            }

            if (is_rising && controller->heater_on) {
                /* Turn heater off early due to rising temp */
                controller->heater_on = false;
            }
            /* If not rising or heater already off, hold current state */
        }

        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
        output.timed_out = controller->timed_out;

        return output;
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
    output.timed_out = controller->timed_out;

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}
